VALUES
  ('social-worker-moex-05270', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列說明何者屬跨科際督導（interdisciplinary supervision）？', '["使用科技產品進行督導工作，以網路線上會議形式進行督導", "有相同需求、觀點或技術層次的個人或一群人，以個別互惠或團體討論的方式進行", "透過有規律或偶發的電子郵件、電話與機構中資深工作者進行督導", "提供同一個案服務的團隊成員，成員具不同的學科背景，形成的團隊督導型態"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05271', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關注組織結構對組織績效具有顯著影響，組織沒有唯一的最佳設計，結構形式、管理和組織 的成效，需視工作的性質及其所處環境特性而定，此論述為何種管理觀點？', '["古典管理觀點（classical approach to management）", "人群關係觀點（human relationship approach）", "系統觀點（system approach）", "權變觀點（contingency approach）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05272', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '照顧管理（care management）的目的在確保有需求的個人在社區中持續生活之一切必要之服 務，下列關於照顧管理的描述何者正確？', '["照顧管理不同於個案管理", "照顧管理僅關注資源的配置與協調", "照顧管理不需要個案工作的知識與技術", "能有效協助多元問題與多元需求之案主"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05273', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '下列何者不是零基預算（zero-based budgeting）的特徵？', '["根據目前的財務狀況來思考方案預算", "機構每年從零開始，不管方案過去或現在是否存在，要為其第二年所提預算做說明及辯護", "理論上，零基預算能精準預測活動、收入與支出", "管理者需客觀決定那些活動在服務輸送中是必要的，那些是不必要的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05274', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '預算是對方案所需花費進行估算活動，具有控制、管理、規劃三個目的。預算的重點在未來 如何分配資源及使用經費。下列敘述何者錯誤？', '["單項預算（line-item）財務控制為主要目的，要求標準化的預算格式設計，標示出所有預 期的收入與支出", "功能性預算（functional）管理為主要目的，關注方案欲提供多少產出、中間輸出與品質輸 出的預期成本", "方案預算（program）以規劃為主要目的，須確定方案輸入和目的、目標的完成，並計算 每項成果的預期成本", "功能性預算系統與方案預算系統都在組織層次收支預算上編列"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05275', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在服務方案的設計與管理上，建置出具有財務控制、管理及規劃的預算系統是重要的，多年 來已有專家學者提出幾種不同的預算設計過程模式，其中將「預算制定視為一種協商過程， 預算決策是利害關係競爭者之間不斷衝突與妥協的最終結果」，為下列何種模式？', '["政治模式", "漸近增值模式", "理性規劃模式", "策略式規劃模式"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05276', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '由於資源有限，募款已是社會服務機構之間相當具競爭性的活動，機構因此需要用心建構募 款的過程，以強化自身在競爭中的優勢地位。若以策略規劃程序來進行募款行動，社會服務 機構執行募款的步驟應為：', '["設定募款目標→分析募款市場→擬定行銷策略與計畫→行動→績效評估", "分析募款市場→設定募款目標→擬定行銷策略與計畫→行動→績效評估", "擬定行銷策略與計畫→分析募款市場→設定募款目標→行動→績效評估", "分析募款市場→擬定行銷策略與計畫→設定募款目標→行動→績效評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05277', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於行銷（marketing）的要素，下列敘述何者錯誤？', '["4P架構：產品（product）、價格（price）、通路（place）、推廣（promotion）", "7P 架構：生產者（producer）、消費者（purchaser）、產品（product）、價格（price）、 通路（place）、推廣（promotion）、調查（probing）", "ABCDE 行銷法：評估（assessment）、強調品牌（brand）、促進溝通（communication）、 探索市場（discovery）、強化體驗（experience）", "4C概念：顧客利益（customer benefit）、顧客成本（cost to the customer）、方便性 （convenience）、溝通（communication）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05278', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社會工作組織中，每個工作者的工作或多或少都與管理有關，因此人人都是管理者。工作 者除了內部的管理，有必須對外經營與機構特別相關的任務環境，下列何者不屬於對外關係 經營策略？', '["社區資源盤點", "擴大接觸面爭取更多支持", "主動改善組織與環境間的關係", "多方經營人際網絡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05279', 'social-worker', 'social-worker-moex-107-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '風險社會（risk society）是當代社會政策關注的重要議題，強調以「服務人群」和「人的價 值」為前提的社會服務組織即需要具有風險管理（risk management）的知能，以能有效管理 可能發生的風險並極小化其帶來的不利影響。風險管理的執行有四個要項，下列說明何者正 確？', '["「風險辨識」是指使用一套有系統的程序來進行廣泛的搜尋，以發掘可能發生風險的事件 及其發生之原因與方式", "「風險分析」是指挑選出需要進一步優先處理的風險，以確定風險處理的優先順序", "「風險評量」是指系統性運用有效資訊，以判定特定事件發生之可能機率及其影響的嚴重 程度", "「風險處理」是指對於不可容忍的風險，列出可將該風險降至最低容忍度的對策，例如 「風險降低」即是組織決定不涉入或退出風險處境的對策"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "9d98621c5f01", "answer_pdf_sha1": "6f17f9099ed5", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
